package energy.lux.access;

import org.junit.Test;
import static org.junit.Assert.*;
import static energy.lux.access.LuxAccessKt.hasRole;

/**
 * Verify functionality using a JWT of a test Keycloak environment.
 */
public class LuxAccessTest {
    // from https://keycloak.zenmo.com/realms/testrealm/protocol/openid-connect/certs
    public String jwk = """
        {
            "kid": "n-X5BeXFe6pIXhDBsDu2mQ2VYc23RSZCFRU5Y6IuzC8",
            "kty": "OKP",
            "alg": "EdDSA",
            "use": "sig",
            "crv": "Ed25519",
            "x": "ILokSbk8EKH-Q1aWo_TguuDRccoSVfEbmGSbm5gcn5I"
        }
    """;

    // expired token with role "dordrecht_view_company_details"
    public String expiredDordrechtToken = "eyJhbGciOiJFZERTQSIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJuLVg1QmVYRmU2cElYaERCc0R1Mm1RMlZZYzIzUlNaQ0ZSVTVZNkl1ekM4In0..pQXotc7ey4bj4Yl_Wor90L-6p90GhmdASBOAl-FySue3bLXvayhmQ0u0bcJBLA5Fcu7EC2kxdWKHHgB3-GVFBw";

    // token with role "dordrecht_view_company_details" valid into year 2045
    public String validDordrechtToken = "eyJhbGciOiJFZERTQSIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJuLVg1QmVYRmU2cElYaERCc0R1Mm1RMlZZYzIzUlNaQ0ZSVTVZNkl1ekM4In0..3vSY9wiS0ZJb3uWJPrU0SHt5xY_sofUwfj9irJ-IyBE7ql9V-tbk0oiV1IYJcYUtG6_791wjdUw4m28mzrocDQ";

    // token with role "papendrecht_view_company_details" valid into year 2045
    public String validPapendrechtToken = "eyJhbGciOiJFZERTQSIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJuLVg1QmVYRmU2cElYaERCc0R1Mm1RMlZZYzIzUlNaQ0ZSVTVZNkl1ekM4In0..Lfh-J710wExN1uig2NgKreXT5Md-IcDkyVGNCaprOAAapIqkJGYFN9aBqnyuH6BAJl7QXtO0nLRWSm4C-ddRDQ";

    // token valid into year 2045 but no claim lux_access_roles.lux_access_roles
    public String validTokenWithNoRoles = "eyJhbGciOiJFZERTQSIsInR5cCIgOiAiSldUIiwia2lkIiA6ICJuLVg1QmVYRmU2cElYaERCc0R1Mm1RMlZZYzIzUlNaQ0ZSVTVZNkl1ekM4In0..wmBXBeE4TLZH8oj5rkAGCNS2uxdWuUvI0Cs_8DygRLjDUUSEsJlgdazCUS3twmwfnzRAYeH9BRXWhmKZrLw3BA";

    @Test
    public void testHasRole() {
        assertTrue(hasRole("dordrecht_view_company_details", validDordrechtToken, jwk));
        assertFalse(hasRole("dordrecht_view_company_details", validPapendrechtToken, jwk));
        assertFalse(hasRole("dordrecht_view_company_details", validTokenWithNoRoles, jwk));

        assertThrows(
                "Access Token has expired",
                LuxAccessException.class,
                () -> hasRole("dordrecht_view_company_details", expiredDordrechtToken, jwk)
        );
    }
}
